const fs = require("fs");
const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  Header, Footer, AlignmentType, HeadingLevel, BorderStyle, WidthType,
  ShadingType, PageBreak, TabStopType, TabStopPosition, LevelFormat,
  PageNumber, NumberFormat
} = require("docx");

// Helper: create a paragraph with mixed formatting
function mixedPara(runs, opts = {}) {
  return new Paragraph({ ...opts, children: runs });
}

function text(t, opts = {}) {
  return new TextRun({ text: t, font: "Cambria", size: 24, ...opts });
}

function bold(t, opts = {}) {
  return text(t, { bold: true, ...opts });
}

function italic(t, opts = {}) {
  return text(t, { italics: true, ...opts });
}

function sup(t, opts = {}) {
  return text(t, { superScript: true, ...opts });
}

function sub(t, opts = {}) {
  return text(t, { subScript: true, ...opts });
}

function spacer(pts = 200) {
  return new Paragraph({ spacing: { after: pts }, children: [] });
}

function heading(level, t) {
  return new Paragraph({
    heading: level,
    children: [new TextRun({ text: t, font: "Cambria" })],
  });
}

function bodyPara(t, opts = {}) {
  return new Paragraph({
    spacing: { after: 120, line: 360 },
    ...opts,
    children: typeof t === "string" ? [text(t)] : t,
  });
}

function equationPara(runs, label) {
  const children = [...runs];
  if (label) {
    children.push(text(`    ${label}`, { italics: true, size: 20, color: "666666" }));
  }
  return new Paragraph({
    spacing: { before: 160, after: 160 },
    alignment: AlignmentType.CENTER,
    children,
  });
}

// Table helper
const border = { style: BorderStyle.SINGLE, size: 1, color: "999999" };
const borders = { top: border, bottom: border, left: border, right: border };
const cellMargins = { top: 60, bottom: 60, left: 100, right: 100 };

function tableCell(runs, opts = {}) {
  return new TableCell({
    borders,
    margins: cellMargins,
    width: { size: opts.width || 4680, type: WidthType.DXA },
    shading: opts.shading ? { fill: opts.shading, type: ShadingType.CLEAR } : undefined,
    children: [new Paragraph({
      children: typeof runs === "string" ? [text(runs, opts.textOpts || {})] : runs,
      alignment: opts.align || AlignmentType.LEFT,
    })],
  });
}

const doc = new Document({
  styles: {
    default: {
      document: { run: { font: "Cambria", size: 24 } },
    },
    paragraphStyles: [
      {
        id: "Heading1", name: "Heading 1", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 32, bold: true, font: "Cambria", color: "1a1a2e" },
        paragraph: { spacing: { before: 360, after: 200 }, outlineLevel: 0 },
      },
      {
        id: "Heading2", name: "Heading 2", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 28, bold: true, font: "Cambria", color: "2d2d44" },
        paragraph: { spacing: { before: 280, after: 160 }, outlineLevel: 1 },
      },
      {
        id: "Heading3", name: "Heading 3", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 26, bold: true, font: "Cambria", color: "3d3d5c" },
        paragraph: { spacing: { before: 200, after: 120 }, outlineLevel: 2 },
      },
    ],
  },
  numbering: {
    config: [
      {
        reference: "bullets",
        levels: [{
          level: 0, format: LevelFormat.BULLET, text: "\u2022",
          alignment: AlignmentType.LEFT,
          style: { paragraph: { indent: { left: 720, hanging: 360 } } },
        }],
      },
      {
        reference: "numbers",
        levels: [{
          level: 0, format: LevelFormat.DECIMAL, text: "%1.",
          alignment: AlignmentType.LEFT,
          style: { paragraph: { indent: { left: 720, hanging: 360 } } },
        }],
      },
    ],
  },
  sections: [
    {
      properties: {
        page: {
          size: { width: 12240, height: 15840 },
          margin: { top: 1440, right: 1440, bottom: 1440, left: 1440 },
        },
      },
      headers: {
        default: new Header({
          children: [new Paragraph({
            alignment: AlignmentType.RIGHT,
            children: [text("Kim, A. (2024) \u2014 Corrected April 2026", { size: 18, color: "888888", italics: true })],
          })],
        }),
      },
      footers: {
        default: new Footer({
          children: [new Paragraph({
            alignment: AlignmentType.CENTER,
            children: [text("Page ", { size: 18, color: "888888" }), new TextRun({ children: [PageNumber.CURRENT], size: 18, color: "888888", font: "Cambria" })]
          })],
        }),
      },
      children: [
        // ==================== TITLE PAGE ====================
        spacer(600),
        new Paragraph({
          alignment: AlignmentType.CENTER,
          spacing: { after: 200 },
          children: [new TextRun({
            text: "Calculating Dark Matter and Dark Energy",
            font: "Cambria", size: 44, bold: true, color: "1a1a2e",
          })],
        }),
        new Paragraph({
          alignment: AlignmentType.CENTER,
          spacing: { after: 100 },
          children: [new TextRun({
            text: "Using Hubble Constant & Critical Density,",
            font: "Cambria", size: 36, color: "2d2d44",
          })],
        }),
        new Paragraph({
          alignment: AlignmentType.CENTER,
          spacing: { after: 400 },
          children: [new TextRun({
            text: "and Its Implications",
            font: "Cambria", size: 36, color: "2d2d44",
          })],
        }),
        new Paragraph({
          alignment: AlignmentType.CENTER,
          spacing: { after: 80 },
          children: [new TextRun({
            text: "E = M \u00D7 (DE/DM)",
            font: "Cambria Math", size: 32, bold: true, color: "1a1a2e",
          })],
        }),
        spacer(400),
        new Paragraph({
          alignment: AlignmentType.CENTER,
          spacing: { after: 80 },
          children: [text("Alex Kim", { size: 28 })],
        }),
        new Paragraph({
          alignment: AlignmentType.CENTER,
          spacing: { after: 80 },
          children: [text("Original: December 2024", { size: 22, color: "666666" })],
        }),
        new Paragraph({
          alignment: AlignmentType.CENTER,
          spacing: { after: 400 },
          children: [text("Corrected: April 2026", { size: 22, color: "666666" })],
        }),
        new Paragraph({
          children: [new TextRun({ break: 1 })],
        }),
        new Paragraph({ children: [new PageBreak()] }),

        // ==================== ABSTRACT ====================
        heading(HeadingLevel.HEADING_1, "Abstract"),
        bodyPara([
          text("This paper outlines the determination of the energy and mass of dark energy (DE) and dark matter (DM) without relying on causality-breaking assumptions or tachyonic interpretations of spacetime. Using foundational principles of thermodynamics, quantum field theory, and observational cosmology, we demonstrate that DE and DM can be understood as manifestations of the quantum fields governing the universe and strictly adhere to the Energy\u2013Mass equivalence principle."),
        ]),
        bodyPara([
          text("A key result emerges: when the mass\u2013energy equivalence relation is applied "),
          italic("across"),
          text(" the dark sector\u2014using DE energy and DM mass\u2014the quantity X = \u221A(E"),
          sub("DE"),
          text(" / M"),
          sub("DM"),
          text(") yields c \u00D7 \u221A(\u03C1"),
          sub("DE"),
          text("/\u03C1"),
          sub("DM"),
          text("), suggesting that the speed of causality is set by the ratio of dark sector energy densities. This result is independent of the Hubble constant."),
        ]),

        // ==================== INTRODUCTION ====================
        heading(HeadingLevel.HEADING_1, "Introduction"),
        bodyPara("The universe\u2019s energy composition is dominated by dark energy (68%) and dark matter (27%), with baryonic matter contributing only 5%. Despite this, the precise nature of DE and DM remains elusive. This work aims to determine their mass and energy contributions using direct inferences from critical density and thermodynamic laws, without invoking speculative causality-breaking constructs such as tachyonic fields or parallel universes."),
        bodyPara("We explore their local and cosmic-scale effects, reconcile their roles in the universe\u2019s expansion and contraction, and note the consistency of the resulting equation with variable speed of light cosmologies."),

        // ==================== KEY PRINCIPLES ====================
        heading(HeadingLevel.HEADING_1, "Key Principles"),

        heading(HeadingLevel.HEADING_2, "1. Critical Density of the Universe"),
        bodyPara("The critical density of the universe is defined as:"),
        equationPara([
          text("\u03C1", { font: "Cambria Math", size: 26 }),
          sub("crit"),
          text(" = 3H\u00B2", { font: "Cambria Math", size: 26 }),
          sub("0"),
          text(" / (8\u03C0G)", { font: "Cambria Math", size: 26 }),
        ]),
        bodyPara("where:"),
        bodyPara([
          text("H"),
          sub("0"),
          text(": Hubble constant. Two values are used: 67.4 km/s/Mpc (Planck/CMBR)"),
          sup("[1]"),
          text(" and 73.0 km/s/Mpc (SH0ES)"),
          sup("[2]"),
        ]),
        bodyPara([
          text("G: Gravitational constant (\u2248 6.67430 \u00D7 10"),
          sup("\u221211"),
          text(" m\u00B3 kg"),
          sup("\u22121"),
          text(" s"),
          sup("\u22122"),
          text(")"),
        ]),

        heading(HeadingLevel.HEADING_2, "2. Energy Density Contributions"),
        bodyPara("According to Planck Collaboration (2018):"),
        new Paragraph({ numbering: { reference: "bullets", level: 0 }, spacing: { after: 60 }, children: [text("Dark energy: 68%")] }),
        new Paragraph({ numbering: { reference: "bullets", level: 0 }, spacing: { after: 60 }, children: [text("Dark matter: 27%")] }),
        new Paragraph({ numbering: { reference: "bullets", level: 0 }, spacing: { after: 120 }, children: [text("Baryonic matter: 5%")] }),

        heading(HeadingLevel.HEADING_2, "3. Volume of the Observable Universe"),
        bodyPara([
          text("The Hubble radius R = c/H"),
          sub("0"),
          text(" defines the scale of the observable universe. Using both Hubble constant values:"),
        ]),
        spacer(60),

        new Table({
          width: { size: 9360, type: WidthType.DXA },
          columnWidths: [2340, 3510, 3510],
          rows: [
            new TableRow({ children: [
              tableCell("Quantity", { width: 2340, shading: "D5E0EB", textOpts: { bold: true } }),
              tableCell("SH0ES (73.0)", { width: 3510, shading: "D5E0EB", textOpts: { bold: true }, align: AlignmentType.CENTER }),
              tableCell("Planck (67.4)", { width: 3510, shading: "D5E0EB", textOpts: { bold: true }, align: AlignmentType.CENTER }),
            ]}),
            new TableRow({ children: [
              tableCell([text("H"), sub("0"), text(" (/s)")], { width: 2340 }),
              tableCell([text("2.3658 \u00D7 10"), sup("\u221218")], { width: 3510, align: AlignmentType.CENTER }),
              tableCell([text("2.1843 \u00D7 10"), sup("\u221218")], { width: 3510, align: AlignmentType.CENTER }),
            ]}),
            new TableRow({ children: [
              tableCell("R (m)", { width: 2340 }),
              tableCell([text("1.267 \u00D7 10"), sup("26")], { width: 3510, align: AlignmentType.CENTER }),
              tableCell([text("1.373 \u00D7 10"), sup("26")], { width: 3510, align: AlignmentType.CENTER }),
            ]}),
            new TableRow({ children: [
              tableCell([text("V (m"), sup("3"), text(")")], { width: 2340 }),
              tableCell([text("8.524 \u00D7 10"), sup("78")], { width: 3510, align: AlignmentType.CENTER }),
              tableCell([text("1.083 \u00D7 10"), sup("79")], { width: 3510, align: AlignmentType.CENTER }),
            ]}),
            new TableRow({ children: [
              tableCell([text("\u03C1"), sub("crit"), text(" (kg/m\u00B3)")], { width: 2340 }),
              tableCell([text("1.001 \u00D7 10"), sup("\u221226")], { width: 3510, align: AlignmentType.CENTER }),
              tableCell([text("8.533 \u00D7 10"), sup("\u221227")], { width: 3510, align: AlignmentType.CENTER }),
            ]}),
          ],
        }),

        spacer(120),

        // ==================== CALCULATIONS ====================
        heading(HeadingLevel.HEADING_1, "Calculations"),

        heading(HeadingLevel.HEADING_2, "1. Total Energy of the Observable Universe"),
        bodyPara("The total energy is obtained from:"),
        equationPara([text("E", { font: "Cambria Math", size: 26 }), sub("total"), text(" = \u03C1", { font: "Cambria Math", size: 26 }), sub("crit"), text(" \u00D7 V \u00D7 c\u00B2", { font: "Cambria Math", size: 26 })]),
        bodyPara([text("This expression simplifies algebraically. Since \u03C1"), sub("crit"), text(" = 3H\u00B2/(8\u03C0G) and V = (4/3)\u03C0(c/H)\u00B3:")]),
        equationPara([text("E", { font: "Cambria Math", size: 26 }), sub("total"), text(" = c\u2075 / (2GH", { font: "Cambria Math", size: 26 }), sub("0"), text(")", { font: "Cambria Math", size: 26 })]),
        bodyPara([bold("Note: "), text("The total energy scales as 1/H"), sub("0"), text(". A larger Hubble constant implies a smaller, denser universe with less total energy within the Hubble volume.")]),

        spacer(60),
        new Table({
          width: { size: 9360, type: WidthType.DXA },
          columnWidths: [2340, 3510, 3510],
          rows: [
            new TableRow({ children: [
              tableCell("", { width: 2340, shading: "D5E0EB" }),
              tableCell("SH0ES", { width: 3510, shading: "D5E0EB", textOpts: { bold: true }, align: AlignmentType.CENTER }),
              tableCell("Planck", { width: 3510, shading: "D5E0EB", textOpts: { bold: true }, align: AlignmentType.CENTER }),
            ]}),
            new TableRow({ children: [
              tableCell([text("E"), sub("total"), text(" (J)")], { width: 2340 }),
              tableCell([text("7.668 \u00D7 10"), sup("69")], { width: 3510, align: AlignmentType.CENTER }),
              tableCell([text("8.305 \u00D7 10"), sup("69")], { width: 3510, align: AlignmentType.CENTER }),
            ]}),
            new TableRow({ children: [
              tableCell([text("E"), sub("DE"), text(" (J) [68%]")], { width: 2340 }),
              tableCell([text("5.214 \u00D7 10"), sup("69")], { width: 3510, align: AlignmentType.CENTER }),
              tableCell([text("5.648 \u00D7 10"), sup("69")], { width: 3510, align: AlignmentType.CENTER }),
            ]}),
            new TableRow({ children: [
              tableCell([text("E"), sub("DM"), text(" (J) [27%]")], { width: 2340 }),
              tableCell([text("2.070 \u00D7 10"), sup("69")], { width: 3510, align: AlignmentType.CENTER }),
              tableCell([text("2.242 \u00D7 10"), sup("69")], { width: 3510, align: AlignmentType.CENTER }),
            ]}),
            new TableRow({ children: [
              tableCell([text("M"), sub("DM"), text(" (kg)")], { width: 2340 }),
              tableCell([text("2.304 \u00D7 10"), sup("52")], { width: 3510, align: AlignmentType.CENTER }),
              tableCell([text("2.495 \u00D7 10"), sup("52")], { width: 3510, align: AlignmentType.CENTER }),
            ]}),
          ],
        }),

        spacer(120),

        heading(HeadingLevel.HEADING_2, "2. Cross-Component Relation: X = \u221A(E_DE / M_DM)"),
        bodyPara([
          text("We now apply the mass\u2013energy equivalence relation across the dark sector, using DE energy and DM mass:"),
        ]),
        equationPara([
          text("X = \u221A(E", { font: "Cambria Math", size: 28, bold: true }),
          sub("DE", { bold: true }),
          text(" / M", { font: "Cambria Math", size: 28, bold: true }),
          sub("DM", { bold: true }),
          text(")", { font: "Cambria Math", size: 28, bold: true }),
        ]),

        bodyPara([bold("Algebraic reduction:"), text(" Substituting the expressions for E"), sub("DE"), text(" and M"), sub("DM"), text(":")]),
        equationPara([text("E", { font: "Cambria Math", size: 24 }), sub("DE"), text(" = 0.68 \u00D7 E", { font: "Cambria Math", size: 24 }), sub("total")]),
        equationPara([text("M", { font: "Cambria Math", size: 24 }), sub("DM"), text(" = 0.27 \u00D7 E", { font: "Cambria Math", size: 24 }), sub("total"), text(" / c\u00B2", { font: "Cambria Math", size: 24 })]),
        equationPara([text("X = \u221A( 0.68 \u00D7 E / (0.27 \u00D7 E / c\u00B2) )", { font: "Cambria Math", size: 24 })]),
        equationPara([text("X = c \u00D7 \u221A(68/27)", { font: "Cambria Math", size: 28, bold: true })]),
        equationPara([text("X = c \u00D7 1.58698...", { font: "Cambria Math", size: 28, bold: true })]),
        equationPara([text("X = 475,765,863 m/s", { font: "Cambria Math", size: 28, bold: true })]),

        spacer(80),
        bodyPara([
          bold("Critical observation: "),
          text("E"),
          sub("total"),
          text(" cancels completely. The result is "),
          bold("independent of H"),
          sub("0", { bold: true }),
          bold(". "),
          text("Both Hubble constant values yield the identical result. The Hubble tension is irrelevant to this derivation."),
        ]),

        // ==================== ERRATA ====================
        heading(HeadingLevel.HEADING_2, "3. Errata from Original Version"),
        bodyPara([bold("Error 1 (SH0ES case): "), text("The original paper reported X = c (299,792,458 m/s) for the SH0ES calculation. This resulted from accidentally using E"), sub("DM"), text(" in the numerator instead of E"), sub("DE"), text(". Since \u221A(E"), sub("DM"), text("/M"), sub("DM"), text(") = \u221A(Mc\u00B2/M) = c trivially, this produced a self-referential result.")]),
        bodyPara([bold("Error 2 (Planck case): "), text("The total energy E"), sub("total"), text("(CMBR) was reported as 6.375 \u00D7 10"), sup("69"), text(" J. The correct value is 8.305 \u00D7 10"), sup("69"), text(" J (a factor of 1.30 error). This arithmetic mistake propagated to give X = 501,847,984 m/s instead of the correct 475,765,863 m/s.")]),
        bodyPara([bold("Correction: "), text("Both cases yield X = c \u00D7 \u221A(68/27) = 475,765,863 m/s identically.")]),

        new Paragraph({ children: [new PageBreak()] }),

        // ==================== DISCUSSION ====================
        heading(HeadingLevel.HEADING_1, "Discussion"),

        heading(HeadingLevel.HEADING_2, "Thermodynamic Consistency"),
        bodyPara([
          text("The calculations confirm that E = Mc\u00B2 applies to each dark sector component independently: E"),
          sub("DM"),
          text(" = M"),
          sub("DM"),
          text(" \u00D7 c\u00B2 and E"),
          sub("DE"),
          text(" = M"),
          sub("DE"),
          text(" \u00D7 c\u00B2. The mass\u2013energy equivalence is preserved within each sector."),
        ]),

        heading(HeadingLevel.HEADING_2, "Cross-Component Relation"),
        bodyPara([
          text("When the relation is applied "),
          italic("across"),
          text(" sectors\u2014E"),
          sub("DE"),
          text(" as the energy and M"),
          sub("DM"),
          text(" as the mass\u2014the result is not c but c \u00D7 \u221A(\u03C1"),
          sub("DE"),
          text("/\u03C1"),
          sub("DM"),
          text("). This cross-component \u201Ceffective velocity\u201D X encodes the energy density ratio of the dark sector."),
        ]),

        heading(HeadingLevel.HEADING_2, "Implication: The Speed of Causality"),
        bodyPara("Rearranging the result:"),
        equationPara([text("X\u00B2 = c\u00B2 \u00D7 (\u03C1", { font: "Cambria Math", size: 26 }), sub("DE"), text(" / \u03C1", { font: "Cambria Math", size: 26 }), sub("DM"), text(")", { font: "Cambria Math", size: 26 })]),
        bodyPara("Or equivalently:"),
        equationPara([text("c\u00B2 = X\u00B2 \u00D7 (\u03C1", { font: "Cambria Math", size: 26 }), sub("DM"), text(" / \u03C1", { font: "Cambria Math", size: 26 }), sub("DE"), text(")", { font: "Cambria Math", size: 26 })]),
        bodyPara([
          text("This can be written as "),
          bold("c\u00B2 \u221D \u03C1"),
          sub("DE", { bold: true }),
          bold(" / \u03C1"),
          sub("DM", { bold: true }),
          text(", suggesting that the speed of causality squared is proportional to the ratio of dark energy density to dark matter density."),
        ]),

        bodyPara("If this relationship is fundamental rather than coincidental, several implications follow:"),
        new Paragraph({ numbering: { reference: "numbers", level: 0 }, spacing: { after: 100, line: 360 }, children: [
          text("The speed of light is not a fixed constant but is "),
          bold("set by the local dark sector energy balance"),
          text(". In regions of higher DM density (e.g., galaxy cores), c would be locally lower."),
        ]}),
        new Paragraph({ numbering: { reference: "numbers", level: 0 }, spacing: { after: 100, line: 360 }, children: [
          text("Since \u03C1"),
          sub("DM"),
          text(" dilutes as the universe expands while \u03C1"),
          sub("DE"),
          text(" remains approximately constant, the ratio \u03C1"),
          sub("DE"),
          text("/\u03C1"),
          sub("DM"),
          text(" increases over cosmic time. This implies c was "),
          bold("lower in the early universe"),
          text(" and is "),
          bold("increasing"),
          text(" with expansion."),
        ]}),
        new Paragraph({ numbering: { reference: "numbers", level: 0 }, spacing: { after: 100, line: 360 }, children: [
          text("The mass\u2013energy equivalence may be re-written in its most general form as:"),
        ]}),
        equationPara([text("E = M \u00D7 (\u03C1", { font: "Cambria Math", size: 30, bold: true }), sub("DE", { bold: true }), text(" / \u03C1", { font: "Cambria Math", size: 30, bold: true }), sub("DM", { bold: true }), text(")", { font: "Cambria Math", size: 30, bold: true })]),
        bodyPara([
          text("where c\u00B2 is replaced by the dark sector density ratio (up to a proportionality constant absorbing units). Einstein\u2019s E = Mc\u00B2 is then the "),
          italic("present-epoch, local"),
          text(" case of this more general relation."),
        ]),

        heading(HeadingLevel.HEADING_2, "Self-Referential Structure"),
        bodyPara("It is worth noting that this equivalence relationship appears self-referential: the speed of causality is defined by the energy content of the universe, and the energy content is measured using the speed of causality. This circularity may not be a defect but rather a fundamental feature of a universe in which spacetime and its contents are not independent."),
        bodyPara([italic("Are we solving the universe, or is the universe solving us?")]),

        spacer(200),

        // ==================== REFERENCES ====================
        heading(HeadingLevel.HEADING_1, "References"),
        bodyPara([text("[1] Planck Collaboration, 2018. Planck 2018 results. VI. Cosmological parameters. "), italic("Astronomy & Astrophysics"), text(", 641, A6.")]),
        bodyPara([text("[2] Riess, A.G. et al., 2019. Large Magellanic Cloud Cepheid Standards Provide a 1% Foundation for the Determination of the Hubble Constant and Stronger Evidence for Physics Beyond \u039BCDM. "), italic("The Astrophysical Journal"), text(", 876(1), 85.")]),

        spacer(200),
        new Paragraph({
          alignment: AlignmentType.CENTER,
          spacing: { before: 400 },
          children: [text("\u2014 \u2014 \u2014", { size: 20, color: "AAAAAA" })],
        }),
        new Paragraph({
          alignment: AlignmentType.CENTER,
          spacing: { before: 100 },
          children: [italic("Corrected April 2026. Original computation December 2024.", { size: 20, color: "888888" })],
        }),
        new Paragraph({
          alignment: AlignmentType.CENTER,
          spacing: { before: 60 },
          children: [italic("Errata identified and verified computationally.", { size: 20, color: "888888" })],
        }),
      ],
    },
  ],
});

Packer.toBuffer(doc).then((buffer) => {
  fs.writeFileSync("/home/claude/E_M_x_DE_over_DM_corrected.docx", buffer);
  console.log("Document created successfully.");
});

