}

function sub(t, opts = {}) {
  return text(t, { subScript: true, ...opts });
}

function spacer(pts = 200) {
  return new Paragraph({ spacing: { after: pts }, children: [] });
}

function heading(level, t) {
  return new Paragraph({
    heading: level,
    children: [new TextRun({ text: t, font: "Cambria" })],
  });
}

function bodyPara(t, opts = {}) {
  return new Paragraph({
    spacing: { after: 120, line: 360 },
    ...opts,
    children: typeof t === "string" ? [text(t)] : t,
  });
}

function equationPara(runs, label) {
  const children = [...runs];
  if (label) {
    children.push(text(`    ${label}`, { italics: true, size: 20, color: "666666" }));
